#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

int T,n,m,nxt[1<<15][4],g[16],p[16],f[1010][1<<15],ones[1<<15],ans[20];
char s[20];

void add(int &x,int y){
    x=(x+y)%mod;
}

int main(){
    scanf("%d",&T);
    for(int i=1;i<1<<15;i++)
        ones[i]=ones[i-(i&(-i))]+1;
    while(T--){
        memset(f,0,sizeof(f));
        scanf("%s%d",s+1,&m);
        n=strlen(s+1);
        for(int i=0,num;i<1<<n;i++){
            for(int j=1;j<=n;j++)
                g[j]=g[j-1]+((i>>j-1)&1);
            num=0;
            for(int j=1;j<=n;j++){
                p[j]=(s[j]=='A'?g[j-1]+1:max(g[j],p[j-1]));
                num|=p[j]-p[j-1]<<j-1;
            }
            nxt[i][0]=num;
            num=0;
            for(int j=1;j<=n;j++){
                p[j]=(s[j]=='C'?g[j-1]+1:max(g[j],p[j-1]));
                num|=p[j]-p[j-1]<<j-1;
            }
            nxt[i][1]=num;
            num=0;
            for(int j=1;j<=n;j++){
                p[j]=(s[j]=='G'?g[j-1]+1:max(g[j],p[j-1]));
                num|=p[j]-p[j-1]<<j-1;
            }
            nxt[i][2]=num;
            num=0;
            for(int j=1;j<=n;j++){
                p[j]=(s[j]=='T'?g[j-1]+1:max(g[j],p[j-1]));
                num|=p[j]-p[j-1]<<j-1;
            }
            nxt[i][3]=num;
        }
        f[0][0]=1;
        for(int i=0;i<m;i++)
            for(int j=0;j<1<<n;j++){
                add(f[i+1][nxt[j][0]],f[i][j]);
                add(f[i+1][nxt[j][1]],f[i][j]);
                add(f[i+1][nxt[j][2]],f[i][j]);
                add(f[i+1][nxt[j][3]],f[i][j]);
            }
        for(int i=0;i<=n;i++) ans[i]=0;
        for(int i=0;i<1<<n;i++)
            add(ans[ones[i]],f[m][i]);
        for(int i=0;i<=n;i++)
            printf("%d\n",ans[i]);
    }
    return 0;
}
